import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

export const title = "Dense Table";

const logs = [
  {
    id: "1",
    event: "User login",
    user: "john@example.com",
    ip: "192.168.1.1",
    time: "10:23 AM",
  },
  {
    id: "2",
    event: "File uploaded",
    user: "jane@example.com",
    ip: "192.168.1.2",
    time: "10:25 AM",
  },
  {
    id: "3",
    event: "Settings changed",
    user: "bob@example.com",
    ip: "192.168.1.3",
    time: "10:28 AM",
  },
  {
    id: "4",
    event: "User logout",
    user: "alice@example.com",
    ip: "192.168.1.4",
    time: "10:30 AM",
  },
  {
    id: "5",
    event: "API request",
    user: "system",
    ip: "192.168.1.5",
    time: "10:31 AM",
  },
  {
    id: "6",
    event: "Database backup",
    user: "system",
    ip: "192.168.1.6",
    time: "10:32 AM",
  },
];

const Example = () => (
  <div className="w-full max-w-4xl rounded-md border bg-background">
    <Table>
      <TableHeader>
        <TableRow className="h-8">
          <TableHead className="py-2">ID</TableHead>
          <TableHead className="py-2">Event</TableHead>
          <TableHead className="py-2">User</TableHead>
          <TableHead className="py-2">IP Address</TableHead>
          <TableHead className="py-2 text-right">Time</TableHead>
        </TableRow>
      </TableHeader>
      <TableBody>
        {logs.map((log) => (
          <TableRow className="h-8" key={log.id}>
            <TableCell className="py-1 text-sm">{log.id}</TableCell>
            <TableCell className="py-1 text-sm">{log.event}</TableCell>
            <TableCell className="py-1 text-sm">{log.user}</TableCell>
            <TableCell className="py-1 text-sm">{log.ip}</TableCell>
            <TableCell className="py-1 text-right text-sm">
              {log.time}
            </TableCell>
          </TableRow>
        ))}
      </TableBody>
    </Table>
  </div>
);

export default Example;

import * as React from "react"

import { cn } from "@/lib/utils"

function Table({ className, ...props }: React.ComponentProps<"table">) {
  return (
    <div
      data-slot="table-container"
      className="relative w-full overflow-x-auto"
    >
      <table
        data-slot="table"
        className={cn("w-full caption-bottom text-sm", className)}
        {...props}
      />
    </div>
  )
}

function TableHeader({ className, ...props }: React.ComponentProps<"thead">) {
  return (
    <thead
      data-slot="table-header"
      className={cn("[&_tr]:border-b", className)}
      {...props}
    />
  )
}

function TableBody({ className, ...props }: React.ComponentProps<"tbody">) {
  return (
    <tbody
      data-slot="table-body"
      className={cn("[&_tr:last-child]:border-0", className)}
      {...props}
    />
  )
}

function TableFooter({ className, ...props }: React.ComponentProps<"tfoot">) {
  return (
    <tfoot
      data-slot="table-footer"
      className={cn(
        "bg-muted/50 border-t font-medium [&>tr]:last:border-b-0",
        className
      )}
      {...props}
    />
  )
}

function TableRow({ className, ...props }: React.ComponentProps<"tr">) {
  return (
    <tr
      data-slot="table-row"
      className={cn(
        "hover:bg-muted/50 data-[state=selected]:bg-muted border-b transition-colors",
        className
      )}
      {...props}
    />
  )
}

function TableHead({ className, ...props }: React.ComponentProps<"th">) {
  return (
    <th
      data-slot="table-head"
      className={cn(
        "text-foreground h-10 px-2 text-left align-middle font-medium whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]",
        className
      )}
      {...props}
    />
  )
}

function TableCell({ className, ...props }: React.ComponentProps<"td">) {
  return (
    <td
      data-slot="table-cell"
      className={cn(
        "p-2 align-middle whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]",
        className
      )}
      {...props}
    />
  )
}

function TableCaption({
  className,
  ...props
}: React.ComponentProps<"caption">) {
  return (
    <caption
      data-slot="table-caption"
      className={cn("text-muted-foreground mt-4 text-sm", className)}
      {...props}
    />
  )
}

export {
  Table,
  TableHeader,
  TableBody,
  TableFooter,
  TableHead,
  TableRow,
  TableCell,
  TableCaption,
}

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
